namespace sv_f85948c64989405f89b2aff7195ca519.Services;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service — one instance per circuit, so each user gets independent state.
/// The circuit survives enhanced navigation, so theme persists across pages.
/// </summary>
public sealed class ThemeService
{
    public ThemeMode Theme { get; private set; } = ThemeMode.System;
    public string AccentColor { get; private set; } = "#0d6efd";

    public event Action? OnChanged;

    public void SetTheme(ThemeMode theme)
    {
        if (Theme == theme) return;
        Theme = theme;
        OnChanged?.Invoke();
    }

    public void SetAccentColor(string color)
    {
        if (AccentColor == color) return;
        AccentColor = color;
        OnChanged?.Invoke();
    }
}

@* Interactive island placed in the static layout — shares the circuit
   (and scoped ThemeService) with all other interactive components. *@
@rendermode InteractiveServer
@implements IDisposable
@inject Services.ThemeService ThemeSvc

<span class="theme-indicator" style="color: @ThemeSvc.AccentColor;"
      title="Current theme">
    @ThemeIcon @ThemeSvc.Theme
</span>

@code {
    private string ThemeIcon => ThemeSvc.Theme switch
    {
        Services.ThemeMode.Light  => "☀️",
        Services.ThemeMode.Dark   => "🌙",
        _                         => "💻"
    };

    protected override void OnInitialized()
        => ThemeSvc.OnChanged += StateHasChanged;

    public void Dispose()
        => ThemeSvc.OnChanged -= StateHasChanged;
}

@* Reusable toggle — drop into any interactive page or layout island. *@
@implements IDisposable
@inject Services.ThemeService ThemeSvc

<button class="btn btn-sm btn-outline-secondary" @onclick="CycleTheme"
        style="border-color: @ThemeSvc.AccentColor;">
    @ThemeLabel
</button>

@code {
    private string ThemeLabel => ThemeSvc.Theme switch
    {
        Services.ThemeMode.Light  => "☀️ Light",
        Services.ThemeMode.Dark   => "🌙 Dark",
        _                         => "💻 System"
    };

    private void CycleTheme()
    {
        var next = ThemeSvc.Theme switch
        {
            Services.ThemeMode.Light  => Services.ThemeMode.Dark,
            Services.ThemeMode.Dark   => Services.ThemeMode.System,
            _                         => Services.ThemeMode.Light
        };
        ThemeSvc.SetTheme(next);
    }

    protected override void OnInitialized()
        => ThemeSvc.OnChanged += StateHasChanged;

    public void Dispose()
        => ThemeSvc.OnChanged -= StateHasChanged;
}

@page "/settings"
@rendermode InteractiveServer
@implements IDisposable
@inject Services.ThemeService ThemeSvc

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-3" style="max-width: 480px; border-color: @ThemeSvc.AccentColor;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="btn-group mb-3" role="group">
            @foreach (var mode in Enum.GetValues<Services.ThemeMode>())
            {
                var active = mode == ThemeSvc.Theme;
                <button class="btn @(active ? "btn-primary" : "btn-outline-primary")"
                        @onclick="() => ThemeSvc.SetTheme(mode)">
                    @mode
                </button>
            }
        </div>

        <h5 class="card-title">Accent Color</h5>

        <input type="color" class="form-control form-control-color mb-2"
               value="@ThemeSvc.AccentColor"
               @onchange="OnColorChanged" />

        <p class="text-muted small">
            Current: <code>@ThemeSvc.AccentColor</code>
        </p>
    </div>
</div>

@code {
    private void OnColorChanged(ChangeEventArgs e)
        => ThemeSvc.SetAccentColor(e.Value?.ToString() ?? "#0d6efd");

    protected override void OnInitialized()
        => ThemeSvc.OnChanged += StateHasChanged;

    public void Dispose()
        => ThemeSvc.OnChanged -= StateHasChanged;
}

